(window.courseContentFiles = window.courseContentFiles || {})["000004/0002"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1 style=\"text-align: center\">НЕВРОЛОГИЧЕН СТАТУС</h1><h3><span class=\"editor-note\" data-note=\"# 1. Менинго-радикуларно дразнене (МРД)\nИзследването на МРД цели да установи наличието на възпалителен процес, кръв в ликворното пространство или механично притискане, които водят до дразнене на мозъчните обвивки или нервните коренчета.\n---\n## **А. Менингеален синдром**\nОбективно се установява чрез защитна мускулна контрактура, целяща да ограничи движението на възпалените менинги.\n* **Вратна ригидност:** Пасивната флексия на главата към гърдите е ограничена и болезнена поради спазъм на еректорите на врата.\n* **Знак на Керниг (Kernig):** Пациентът е по гръб с крак, свит в тазобедрената и коленната става под 90°. При опит за пасивно екстензиране (изправяне) на коляното се появява силна болка и съпротива.\n* **Знак на Брудзински (Brudzinski):** * **Горен:** При пасивна флексия на главата към гърдите, пациентът неволево свива краката в коленните и тазобедрените стави. * **Долен:** При пасивен натиск върху симфизата или флексия на единия крак, се наблюдава рефлекторна флексия на срещуположния крак.\" id=\"note-1776075956178-7\">1. Менинго-радикуларно дразнене (МРД)</span></h3><ul><li><strong>Наличност:</strong> Липсва / Налично</li><li><strong>Специфични белези:</strong></li><ul><li>Брудзински: (+/-)</li><li>Керниг: (+/-)</li></ul></ul><h3><span class=\"editor-note\" data-note=\"# 2. Черепно-мозъчни нерви (ЧМН)\nИзследването на ЧМН позволява топографска диагностика на мозъчния ствол и пътищата на черепномозъчната инервация.\n---\n## **А. Окуломоторика и Зенични реакции (II, III, IV, VI ЧМН)**\n* **Зеници:** * **Изокория:** Еднакъв диаметър (норма). * **Анизокория:** Разлика в диаметъра (патология). * **Мидриаза:** Разширени зеници. * **Миоза:** Силно свити зеници.\n* **Реакция на светлина:** Директна и консенсуална (съдружна). Липсата ѝ насочва към лезия на n. oculomotorius или зрителния нерв.\n* **Подвижност на булбусите:** Оценява се за парализи на инервацията: * **n. III (oculomotorius):** Птоза, мидриаза, отклонение на булбуса навън и надолу. * **n. IV (trochlearis):** Диплопия при гледане надолу и навътре. * **n. VI (abducens):** Невъзможност за отвеждане на булбуса навън (абдукция).\n* **Нистагъм:** Ритмични итеративни движения на булбусите. Описва се по посока (хоризонтален, вертикален, ротаторен) и тип (вестибуларен или централен).\n---\n## **Б. n. Facialis (VII ЧМН)**\nКритично е разграничаването на типа пареза за локализация на лезията:\n* **Централна пареза:** Засяга само долния мимически етаж (устния ъгъл). Челото се сбръчква симетрично. Локализация: Контралатерален пирамиден път над ядрото на нерва.\n* **Периферна пареза (на Бел):** Пълна хемифациална парализа (засегнати са и горен, и долен клон). Налице е лагофталм (невъзможност за затваряне на окото) и заличени гънки на челото. Локализация: Ядро или самият нерв ипсилатерално.\n---\n## **В. Булбарна група и n. Hypoglossus (XII ЧМН)**\n* **n. XII (Подезичен нерв):** Изследва се трофиката и позицията на езика. * **Език по средна линия:** Норма. * **Отклонение:** Езикът девиатира към страната на парезата при периферна лезия и към страната на здравата хемисфера при централна.\n* **Дисфония / Дизартрия:** Оценяват се функциите на IX и X ЧМН (гласни връзки и меко небце).\n---\n### **Академична интерпретация:**\nПри наличие на **анизокория** в комбинация с **птоза**, винаги се търси синдром на Клод-Бернар-Хорнер (симпатикова лезия) или компресия на n. III (напр. при херниация). Наличието на **нистагъм** изисква диференциална диагноза между вестибуларен апарат и малкомозъчни пътища в ствола.\" id=\"note-1776075823623-6\">2. Черепно-мозъчни нерви (ЧМН)</span></h3><ul><li><strong>Зеници:</strong> Еднакви (Изокория) / Анизокория / Мидриаза / Миоза</li><ul><li><em>Реакция на светлина:</em> Реагират / Не реагират</li></ul><li><strong>Очни булбуси:</strong> Подвижни във всички посоки</li><ul><li><em>Отклонения:</em> Парализа на n. III, IV или VI / Птоза / Диплопия</li><li><em>Движение:</em> Не отвежда (наляво / надясно / нагоре / надолу) – за кое око?</li><li><em>Нистагъм:</em> Хоризонтален / Вертикален / Ротаторен / Изчерпващ се</li></ul><li><strong>n. Facialis (VII ЧМН):</strong> Без пареза / Централна пареза / Периферна пареза (на Бел)</li><li><strong>n. Hypoglossus (XII ЧМН):</strong> Език по средна линия / Отклонен (наляво/надясно)</li></ul><h3><span class=\"editor-note\" data-note=\"# 3. Двигателна дейност (ДД)\nДвигателната дейност се оценява чрез обем на активните движения, мускулна сила и специализирани тестове за дефицит.\n## **А. Проби за латентни парези (ПЛП) / Дрифт тестове**\nТези проби са по-чувствителни от директното изследване на мускулната сила, тъй като разчитат на постуралния контрол. Целта е да се установи лека (латентна) слабост, която пациентът иначе успява да компенсира волево.\n* **Проба на Мингацини (Mingazzini):** * **За горни крайници:** Пациентът държи ръцете си хоризонтално напред с длани нагоре и затворени очи. При пареза се наблюдава постепенно „пропадане“ (дрифт) на засегнатия крайник, често придружено от пронация (завъртане на дланта надолу). * **За долни крайници:** Пациентът е по гръб с флектирани в бедрата и коленете крака под ъгъл 90°. Парезата се обективизира чрез неспособност за задържане на позицията и пропадане на подбедрицата.\n---\n## **Б. Топографска класификация на парезите**\nВ зависимост от броя и разпределението на засегнатите крайници, дефицитът се класифицира академично по следния начин:\n| Термин | Описание на дефицита | Клинична локализация (често) |\n| :--- | :--- | :--- |\n| **Монопареза** | Засягане на един крайник (ръка или крак). | Корова проекция (Gyrus praecentralis) или периферен корен/нерв. |\n| **Хемипареза** | Засягане на едната половина на тялото (ръка и крак). | Противоположна хемисфера (Capsula interna, ствол). |\n| **Парапареза** | Засягане на двата долни крайника. | Гръбначен мозък (торакално/лумбално ниво) или парасагитална кора. |\n| **Квадрипареза** | Засягане на четирите крайника. | Високо цервикално ниво на гръбначния мозък или мозъчен ствол. |\n---\n## **В. Степен на двигателния дефицит**\nКлинично се прави разлика между **пареза** (частична слабост) и **плегия** (пълна липса на волево движение).\n* **Пареза:** Понижена мускулна сила, но запазена възможност за движение.\n* **Плегия (Парализа):** 0/5 мускулна сила по скалата на Loven.\n---\" id=\"note-1776075574269-5\">3. Двигателна дейност (ДД)</span></h3><ul><li><strong>Проби за латентни парези (ПЛП/Дрифт):</strong></li><ul><li>Без парези – задържа четирите крайника еднакво.</li><li>Налични парези: Монопареза / Хемипареза / Парапареза (описва се конкретен крайник).</li></ul></ul><h3><span class=\"editor-note\" data-note=\"# 4. Рефлексна дейност\nРефлексната дейност е израз на интегритета на сегментния апарат на гръбначния мозък и супраспиналния контрол.\n---\n## **А. Сухожилно-надкостни рефлекси (СНР)**\nСНР са моносинаптични миотатични рефлекси. Оценяват се по интензитет и симетрия.\n* **Класификация на интензитета:** * **Хипорефлексия/Арефлексия:** Понижени или липсващи рефлекси. Характерни за **периферна увреда** (прекъсната рефлексна дъга – предни рога, коренчета, периферен нерв). * **Умерено живи:** Физиологична норма. * **Хиперрефлексия:** Повишени рефлекси с разширена рефлексогенна зона и евентуално **клонус** (на пателата или стъпалото). Характерна за **централна увреда** (отпадане на инхибиторния контрол на пирамидния път).\n* **Симетрия:** * **Анизорефлексия (Л ≠ Д):** Винаги патологичен белег, насочващ към огнищна увреда.\n* **Основни рефлекси и нива:** * Бицепсов (*m. biceps brachii*): **C5 – C6** * Трицепсов (*m. triceps brachii*): **C7 – C8** * Пателарен (*m. quadriceps femoris*): **L2 – L4** * Ахилов (*m. triceps surae*): **L5 – S2**\n---\n## **Б. Патологични рефлекси (ПР)**\nНаличието на патологични рефлекси при възрастни винаги е белег за органична увреда на **пирамидния тракт** (*tractus corticospinalis*).\n### **1. Екстензорни стъпални рефлекси (Група на Бабински)**\nПри тези рефлекси крайният отговор е идентичен – дорзална флексия на палеца.\n* **Рефлекс на Бабински (Babinski):** Предизвиква се чрез дразнене на външния ръб на стъпалото.\n* **Рефлекс на Опенхайм (Oppenheim):** Силен натиск с палеца и показалеца по предния ръб на тибията отгоре надолу.\n* **Рефлекс на Гордон (Gordon):** Силно притискане на мускулатурата на прасеца (*m. gastrocnemius*).\n* **Рефлекс на Шефер (Schäffer):** Силно притискане на Ахиловото сухожилие.\n### **2. Флексорни стъпални рефлекси**\nПатологичният отговор е бърза плантарна флексия на пръстите.\n* **Рефлекс на Росолимо (Rossolimo):** Рязък удар с върха на пръстите по плантарната повърхност на дисталните фаланги на II-V пръст.\n* **Рефлекс на Жуковски (Zhukovsky):** Удар с чукче по дланната повърхност на стъпалото, непосредствено под основата на пръстите.\n* **Рефлекс на Бехтерев-Мендел:** Удар с чукче по дорзалната повърхност на стъпалото в областта на метатарзалните кости.\n### **3. Патологични рефлекси за горни крайници**\nБелези за пирамидна дезинхибиция, проявяващи се чрез флексия на пръстите.\n* **Рефлекс на Хофман (Hoffmann):** Рязко „прещракване“ на нокътната фаланга на III пръст надолу. (+) резултат: флексия на палеца и показалеца.\n* **Рефлекс на Тромнер (Trömner):** Удар с върха на пръстите по палмарната повърхност на дисталната фаланга на III пръст. (+) резултат: флексия на всички пръсти.\" id=\"note-1776075359217-4\">4. Рефлексна дейност</span></h3><ul><li><strong>Сухожилно-надкостни рефлекси (СНР):</strong></li><ul><li>Умерено живи / Хиперрефлексия / Хипорефлексия</li><li><em>Симетрия:</em> Л = Д (сравнително)</li></ul><li><strong>Патологични рефлекси (ПР):</strong></li><ul><li>Тук се включват всички налични патологични, но основно Бабински.</li><li>Бабински: (-) двустранно / (+) вляво / (+) вдясно / (+) двустранно</li></ul></ul><h3><span class=\"editor-note\" data-note=\"# 5. Сетивност\nИзследва се чрез сравнителна стимулация на симетрични участъци. При липса на дефицит се вписва: **„Сетивност – съхранена за всички модалности“**.\n## **А. Качествени промени (Състояние)**\n* **Хипестезия:** Намалена чувствителност.\n* **Анестезия:** Пълна липса на сетивност.\n* **Хиперестезия:** Повишена чувствителност (често при коренчево дразнене).\n* **Парестезии:** Спонтанни усещания за „мравучкане“ или „иглички“.\n* **Дисестезия:** Извратено усещане (напр. допир се усеща като болка).\n## **Б. Типове на сетивно засягане (Локализация)**\nТова е ключовият момент за определяне нивото на лезията:\n| Тип засягане | Клинична характеристика | Анатомична локализация |\n| :--- | :--- | :--- |\n| **Монотип** | Засягане на един крайник. | Периферен нерв или коренче (*Plexus*). |\n| **Паратип** | Двустранно засягане (напр. двата крака). | Гръбначен мозък (напр. трансверзален миелит). |\n| **Хемитип** | Едностранно засягане (лява или дясна половина). | Таламус или задно бедро на *Capsula interna*. |\n| **Дистален тип** | Тип „ръкавици и чорапи“ (симетрично). | Полиневропатия. |\n| **Сегментен тип** | Засягане на конкретен дерматом. | Задни рога или коренчета на гръбначния мозък. |\n---\n## **В. Проводни пътища и модалности (Академичен аспект)**\nТрябва да различаваме кои пътища са засегнати:\n1. **Екстероцептивна (Повърхностна) сетивност:** Болка, температура и допир. * *Път:* **Tractus spinothalamicus**. Кръстосва се на сегментно ниво в гръбначния мозък.\n2. **Проприоцептивна (Дълбока) сетивност:** Вибрационен усет, ставно-мускулно чувство (позиция на тялото). * *Път:* **Funiculus posterior** (Задни стълбове – снопчета на Гол и Бурдах). Кръстосва се на ниво продълговат мозък (*Lemniscus medialis*).\" id=\"note-1776075245545-3\">5. Сетивност</span></h3><ul><li><strong>Състояние:</strong> Съхранена / Хиперестезия / Хипестезия</li><li><strong>Тип на засягане:</strong> Монотип / Паратип / Хемитип</li></ul><h3><span class=\"editor-note\" data-note=\"### 6. Координация и Статика\nТази част от статуса оценява волевата моторна прецизност и поддържането на равновесие. При липса на отклонения се вписва: **„Координация и статика – интактни“** или **„Изследвани без патологични отклонения“**.\n#### **А. Динамична координация (Евметрия и Тракция)**\nОценява се функцията на малкомозъчните хемисфери.\n* **Носопоказалична проба (НПП):** Изследва горните крайници. * *Патология:* **Дизметрия** (нарушен мащаб на движението) – хиперметрия (прехвърляне на целта) или хипометрия (недостигане). * **Интенционен тремор:** Кинетичен тремор с честота **3-5 Hz**, който се засилва при приближаване към обекта. Белег за увреда на *nucleus dentatus* или горното малкомозъчно краче.\n* **Проба Пета-стъпало (ПСП):** Изследва долните крайници. * *Патология:* Атаксия или дизметрия при плъзгане на петата по тибията.\n#### **Б. Статична координация и Постурален контрол**\n* **Проба на Ромберг:** Пациентът стои със събрани стъпала и протегнати ръце. * **Отрицателен:** Стабилен стоеж. * **Положителен (Церебеларен тип):** Нестабилност и залитане (латеропулсия) към страната на лезията. Не се влияе съществено от затварянето на очите. * **Положителен (Сензорен тип):** Нестабилността се появява или рязко се засилва само при затваряне на очите (белег за увреда на задна стълбова сетивност – *funiculus posterior*).\n#### **В. Малкомозъчни феномени**\n* **Адиадохокинеза:** Невъзможност за бърза смяна на антагонистични движения (пронация/супинация).\n* **Асинергия (на Бабински):** Нарушена координация между отделните мускулни групи при комплексни движения.\n---\n### **Академични бележки за локализация:**\n1. **Вермис (червей) на малкия мозък:** Увредата му води до **трунко-атаксия** (нестабилност на тялото и походката).\n2. **Хемисфери на малкия мозък:** Увредата им води до ипсилатерална **дизметрия и тремор** в крайниците.\" id=\"note-1776075169477-0\">6. Координация и Статика</span></h3><ul><li><strong>Носопоказалична проба (НПП):</strong> Изпълнява правилно</li><ul><li><em>Отклонения:</em> Дизметрия (Хипо- / Хиперметрия); Интенционен тремор (ляво/дясно)</li></ul><li><strong>Проба Пета-стъпало:</strong> Изпълнява правилно / Дизметрия</li><li><strong>Ромберг:</strong> Отрицателен / Положителен (церебеларен тип)</li><li>Ако е нормален, не се пише или \"изследва се без отклонения\".</li><li><em>Забележка:</em> При пареза или болка – „НПП не се изследва достоверно поради...“</li></ul><h3><span class=\"editor-note\" data-note=\"# 7. Туловищни рефлекси (ТР)\nТези рефлекси се изследват чрез леко и бързо щрихово дразнене на кожата. При норма се означават като **„Запазени“**, а при патология – като **„Липсват“** или **„Отслабени“**.\n## **А. Коремни рефлекси (Reflexus abdominalis)**\nИзследват се в три нива (горно, средно и долно) чрез дразнене от периферията към медиалната линия. Техните рефлексни дъги преминават през специфични сегменти на гръбначния мозък:\n* **Горни коремни (Epigastric):** Сегменти **Th7 – Th8**. (Дразнене под ребрената дъга).\n* **Средни коремни (Mesogastric):** Сегменти **Th9 – Th10**. (Дразнене на нивото на пъпа).\n* **Долни коремни (Hypogastric):** Сегменти **Th11 – Th12**. (Дразнене над ингвиналната гънка).\n## **Б. Кремастерен рефлекс (Reflexus cremastericus)**\nИзследва се само при мъже чрез дразнене на кожата по вътрешната повърхност на бедото.\n* **Рефлексна дъга:** Сегменти **L1 – L2**.\n* **Ефект:** Повдигане на тестиса от същата страна.\n## **В. Анален рефлекс (Reflexus analis)**\nИзследва се чрез дразнене на кожата около ануса.\n* **Рефлексна дъга:** Сегменти **S4 – S5** (конус на гръбначния мозък).\n---\n# **Клинично значение и локализация:**\n1. **Пирамидна увреда (Горноневронална):** При инсулт или тумор, засягащ пирамидния път над съответното сегментно ниво, коремните рефлекси **изчезват** от страната на парезата. Това е ранен белег за централна увреда.\n2. **Сегментна увреда (Нисконевронална):** Ако липсва само един от коремните рефлекси (напр. само долните), това локализира нивото на увреда в конкретния гръбначномозъчен сегмент (в случая Th11-Th12).\n3. **Физиологични вариации:** Коремните рефлекси могат да липсват при възрастни хора, при пациенти със силно отпусната коремна стена, след множество коремни операции или при затлъстяване, без това да е патология.\" id=\"note-1776075184125-1\">7. Туловищни рефлекси (ТР)</span></h3><ul><li><strong>Коремни, кремастерни и др.:</strong> Запазени / Липсват</li></ul><h3><span class=\"editor-note\" data-note=\"# 8. Висши корови функции (ВКФ) – Академичен анализ\nВКФ представляват висшата степен на интегративна дейност на ГМ. При норма (интактна кора) се означават като **съхранени**. Нарушенията им обикновено са фокални и корелират със специфични цитоархитектонични полета.\n## **А. Афазии (Езикова дезорганизация)**\nНарушения в кодирането и декодирането на езиковата информация при запазен слух и артикулационен апарат.\n* **Моторна афазия (на Broca):** * **Локализация:** Полета **44** и **45** по Бродман (*Gyrus frontalis inferior* на доминантната хемисфера). * **Характеристика:** Нарушен езиков праксис. Пациентът е в състояние да инициира мисълта, но не може да я превърне в говорни символи (нефлуентна реч).\n* **Сензорна афазия (на Wernicke):** * **Локализация:** Поле **22** по Бродман (*Gyrus temporalis superior* на доминантната хемисфера). * **Характеристика:** Нарушена редискодировка на звуковите сигнали в смислови понятия. Пациентът говори гладко, но безсмислено (логорея, парафазии), липсва самокритичност.\n* **Смесена (Глобална) афазия:** * **Локализация:** Масивна лезия, обхващаща перисилвиевата зона (полета **22, 44, 45**).\n---\n## **Б. Агнозии (Гностични нарушения)**\nНевъзможност за интерпретация на сетивни стимули при съхранена първична сетивност.\n* **Зрителна агнозия:** Полета **18** и **19** (вторична и третична зрителна кора, окципитален лоб). Пациентът вижда, но не разпознава обекта.\n* **Астереогнозия:** Полета **5** и **7** (париетален лоб). Невъзможност за разпознаване на предмети чрез опипване със затворени очи.\n* **Пространствено хемиигнориране (Neglect):** Свързва се с поле **40** (Gyrus supramarginalis) в **недоминантната** (обикновено дясна) хемисфера.\n---\n## **В. Апраксии (Праксисни нарушения)**\nНарушение на целенасочените, научени двигателни навици.\n* **Идеомоторна апраксия:** Локализира се в поле **40** на левия париетален лоб. Пациентът не може да изпълни символично движение по команда (например „помахайте за довиждане“).\n* **Конструктивна апраксия:** Свързва се с десния париетален лоб (полета **7** и **39**). Пациентът не може да копира елементарни геометрични фигури.\" id=\"note-1776075212494-2\">8. Висши корови функции (ВКФ)</span></h3><ul><li><strong>Състояние:</strong> Съхранени</li><li><strong>Афазии:</strong> Моторна / Сензорна / Смесена</li><li><strong>Агнозии:</strong> Липсват / Налични</li></ul><h3><span class=\"editor-note\" data-note=\"# 9. Допълнителни изследвания (при показания)\nТази секция обективизира функционалния капацитет и локализира специфични коренчеви или малкомозъчни дефицити.\n---\n## **А. Мускулна сила (Loven / MRC Scale)**\nОценява се чрез преодоляване на активно съпротивление:\n* **5/5:** Нормална сила срещу максимално съпротивление.\n* **4/5:** Движение срещу гравитация и умерено съпротивление (**Активна пареза**).\n* **3/5:** Движение срещу гравитация, но не и срещу съпротивление (**Средна пареза**).\n* **2/5:** Движение само в хоризонтална равнина при елиминирана гравитация (**Тежка пареза**).\n* **1/5:** Видимо мускулно съкращение без движение в ставата (**Фликър**).\n* **0/5:** Пълна липса на каквато и да е активност (**Плегия / Парализа**).\n---\n## **Б. Походка (Локомоция)**\nПоходката е ключов диагностичен белег за типа на двигателната увреда:\n* **Нормална:** Симетрична, със запазени физиологични синкинезии (движения на ръцете).\n* **Хемипаретична (Походка тип &quot;Коса&quot; / Синдром на Вернике-Ман):** Поради спастичност кракът е функционално по-дълъг и се замята в полукръг (**Циркумдукция**). Ръката обикновено е във флексия и аддукция. (**При лезия на горния мотоневрон** - инсулт).\n* **Спастично-паретична (&quot;Ножична&quot; походка):** Силна спастичност на аддукторите води до триене и кръстосване на коленете при стъпване. (При ДЦП или двустранни спинални лезии).\n* **Перонеална (&quot;Степаж&quot;/ &quot;Петлена&quot; походка):** Невъзможност за дорзална флексия на стъпалото (&quot;висящо стъпало&quot;). Пациентът вдига коляното високо, за да не закачи пръстите в земята. (Пареза на *n. peroneus* или коренче L5).\n* **Атаксична (Малкомозъчна / &quot;Пиянска&quot; походка):** На широка основа, залитаща, с нарушена координация на центъра на тежестта.\n* **Паркинсонова (Пропулсивна):** Ситни, ускоряващи се крачки, наведена напред поза и липса на движение в ръцете (**Ахейрокинеза**).\n* **Миопатична (&quot;Патешка&quot; походка):** Клатене на таза встрани поради слабост на мускулите на тазовия пояс (Симптом на Тренделенбург).\n---\n## **В. Разтежни феномени (Радикулерно дразнене)**\nУстановяват механична компресия или възпаление на спиналните коренчета:\n* **Знак на Lasegue:** Поява на остра болка по хода на *n. ischiadicus* при пасивно повдигане на изпънатия крак (позитивен под 60°).\n* **Знак на Neri:** Поява на болка в лумбалния отдел при максимално навеждане на главата към гърдите.\n---\n## **Г. Малкомозъчни проби**\nИзследват прецизността, ритъма и координацията на волевите движения:\n* **Диадохокинеза:** Способност за бърза и ритмична смяна на антагонистични движения (пронация/супинация). Нарушението се нарича **Адиадохокинеза**.\n* **Проба &quot;Колело&quot;:** Ритмично имитиране на въртене на педали с ръцете – тества синхронната координация.\n* **Феномен на Стюарт-Холмс:** Проба за обратен тласък – изследва способността на антагонистите да спрат рязко волево движение при внезапно отпадане на съпротивлението.\" id=\"note-1776076170902-8\">9. Допълнителни изследвания (при показания)</span></h3><ul><li><strong>Мускулна сила:</strong> (оценка по 5-степенната скала)</li><li><strong>Походка:</strong> Нормална / Атаксична / Хемипаретична / Спастична</li><li><strong>Разтежни феномени:</strong> Ласег (+/-) / Нери (+/-)</li><li><strong>Малкомозъчни проби:</strong> Диадохокинеза, Колело и др.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: left\"><span class=\"editor-note\" data-note=\"# Клиничен анализ: Случай №1 (Вестибуло-атактичен и Радинкуларен синдром)\n## 1. Фокус върху Анамнезата\nТук виждаме комбинация от три отделни проблема, които трябва да разграничим:\n* **Световъртеж и главоболие:** 3-месечната давност подсказва за хроничен процес. При пациент с толкова тежка сърдечно-съдова история, първата мисъл трябва да бъде **съдова недостатъчност в вертебро-базиларната система** (лошо оросяване на малкия мозък и ствола).\n* **Радикулерна болка:** Болката в кръста към левия крак е класически признак за засягане на коренчетата на седалищния нерв (L5-S1).\n* **Сърдечно-съдов риск:** Множеството стентове и хипертонията III стадий правят този пациент „високорисков“ за нов съдов инцидент (инсулт).\n---\n## 2. Патоморфологичен анализ на статуса\n### **А. Вестибуларен апарат**\n* **Дребен хоризонтален нистагъм:** Това е обективното доказателство за световъртежа. Хоризонталният нистагъм обикновено е признак за дразнене на вестибуларните ядра или периферния вестибуларен апарат.\n* **Ромберг (стабилна):** Фактът, че е стабилна, е добър признак – означава, че вестибуларният дефицит е компенсиран или лек.\n### **Б. Периферна нервна система**\n* **Точки на Вале (Valleix):** Това са специфични места по хода на седалищния нерв, където той е най-повърхностен. Болезнеността там потвърждава диагнозата **L-S радикулит** (възпаление или притискане на коренче, често от дискова херния).\n* **Отслабени СНР (Л=Д):** Симетричното отслабване на рефлексите при възрастни пациенти често се дължи на съпътстваща полиневропатия (например диабетна или съдова) или дегенеративни промени в гръбнака.\n### **В. Двигателна сфера**\n* **Липса на ЛП (латентни парези):** Най-важният негативен резултат тук. Това означава, че въпреки световъртежа и болката, няма данни за пирамидна увреда (инсулт).\" id=\"note-1776074109818-1\">Пример 1</span></h1><p><strong>АНАМНЕЗА</strong>: Снета по данни на болната. С оплаквания от 3 месеца от пристъпен световъртеж, главоболие обхващащо лявата половина на главата. Съобщава и за болки в кръста, разпространяващи се към левия крак и безсъние. Консултирана с амб. невролог и насочена за планова хоспитализация.</p><p><strong>ПРИДРУЖАВАЩИ ЗАБОЛЯВАНИЯ</strong>: ИБС. Нестабилна ангина пекторис – акцелерирала форма (МКБ І20.0). Коронарна атеросклероза - едносъдова болест, проходими стентове (МКБ І25.0). Състояние след PCI на RCA с DES (м.05.2023г., м.02.2023г. и м.11.2022г.). Хипертонична болест ІІІ стадий, умерена степен, сърдечна форма, хипертонично сърце (МКБ І11.9). Дислипидемия (МКБ Е78.0). Хроничен гастрит (МКБ К29.5).</p><p><strong>ОБЕКТИВЕН СТАТУС</strong>: Жена на видима възраст отговаряща на действителната. Ало- и автопсих. ориент. ССС: ритм. сърд. дейност, АН 130/70, СЧ 75. ДС: чисто везикуларно дишане. Корем: мек, неболезнен. Крайници: без отоци.</p><p><strong>НЕВРОЛОГИЧЕН СТАТУС</strong>: Липсва МРД. ЧМН: очни булб. подвижни във всички посоки, липсва диплопия, дребен хоризонтален нистагъм, без лицева асиметрия. ДД: запазени активни движения за 4-те к-ка, без ЛП, отслабени двустр. СНР Л=Д, без ПР. Сетивност: болезн. в т. Вале в Л-отдел. Координация: НПП-б.о., Ромберг-стабилна. ТР: контр. ВКФ: б.о.</p><h1 style=\"text-align: left\"><span class=\"editor-note\" data-note=\"# Клиничен анализ: Случай №2 (Синдром на Horner и суспектен Pancoast тумор)\n## 1. Фокус върху Анамнезата (Червените флагове)\nТози пациент представя класическа комбинация, която трябва веднага да събуди съмнение за онкологичен процес във върха на белия дроб:\n* **Птоза:** Част от симпатиковата инервация на окото.\n* **Дисфония (пареза на гласна връзка):** Увреда на *n. laryngeus recurrens*.\n* **Патологична фрактура:** Счупване на ключица при &quot;минимално движение&quot; е признак за метастатична деструкция на костта.\n* **B-симптоматика:** Редукция на тегло (15 кг за 3 седмици) и кашлица при тежък пушач (40 пак/год).\n---\n## 2. Патофизиологичен и патоморфологичен анализ\n### **А. Синдром на Claude-Bernard-Horner**\nВ статуса е описана **птоза на ляв клепач**. Въпреки че липсва описание на миоза, комбинацията с болка в ръката насочва към притискане на симпатиковия ствол от тумор във върха на белия дроб (Тумор на Панкост).\n### **Б. Изолирана дисфония (n. vagus / n. laryngeus recurrens)**\nТуморът в левия белодробен връх често обхваща левия рекурентен нерв, който прави примка около аортната дъга. Това обяснява &quot;глухия&quot; говор и парезата на гласната връзка.\n### **В. Пирамидният белег: Бабински (+)**\nТова е най-критичният момент в неврологичния статус. **Бабински (+) вляво** означава увреждане на горния мотоневрон (пирамидния път). При този пациент това най-вероятно сигнализира за:\n1. **Метастаза в главния мозък** (десностранна прецентрална извивка).\n2. **Притискане на гръбначния мозък** (при метастаза в прешлените).\" id=\"note-1776074012796-0\">Пример 2</span></h1><p><strong>АНАМНЕЗА</strong>: Снета по данни на болния. Постъпва сам в СПО по спешност. Пациентът споделя, че лявото му око е по-затворено, появила се болка и слабост в лявата ръка, затруднен и глух говор, започнал постепенно с дрезгавина, впоследствие до изявени трудности при говорене. Наскоро преживял фрактура на лявата ключица при минимално физическо движение (протягане за качване в автобус). Съобщава за кашлица от доста време, редукция на тегло около 15 кг за 2-3 седмици. Посетил УНГ – данни за пареза на лява гласна връзка. Пушач 40 пакетогодини.</p><p><strong>ОБЕКТИВЕН СТАТУС</strong>: Контактен, адекватен, ориентиран.</p><p><strong>НЕВРОЛОГИЧЕН СТАТУС</strong>: МРД: липсва. ЧМН: птоза на ляв клепач, очни булбуси подвижни във всички посоки, зеници еднакво реагиращи на светлина, без нистагъм и диплопия. Дисфония. Език на ср. линия, без налична лезия на VII ЧМН. ДД: ПЛП не се изследва достоверно за лява ръка поради фрактура на лява клавикула; задържа дясна ръка и долни крайници. СНР: ум. живи Л=Д, Бабински (+) пол. вляво. Координация: НПП изпълнява правилно вдясно, вляво не се изследва. Сетивност: съхранена. ТР: контр. ВКФ: съхранени.</p><h1 style=\"text-align: left\"><span class=\"editor-note\" data-note=\"# Клиничен анализ: Случай №3 (Парализа на Бел / Bell's Palsy)\n## 1. Фокус върху Анамнезата (Диференциална диагностика)\n* **Внезапно начало:** Симптомите се появяват сутринта – изтичане на течности и изкривяване на лицето. Това често плаши пациентите, че получават инсулт.\n* **Хиперакузис (неприятен шум):** Това е изключително важен симптом! Той показва, че увредата е **периферна** и е локализирана високо в костния канал, преди отделянето на *n. stapedius* (който инервира мускула, заглушаващ силните звуци).\n* **Променен вкус (Ageusia/Dysgeusia):** Показва засягане на *chorda tympani* (клон на VII ЧМН), което отново потвърждава периферния тип лезия.\n---\n## 2. Патофизиологичен анализ на статуса\n### **А. Периферна vs. Централна лезия на VII ЧМН**\nВ статуса е записано &quot;Парализа на Бел вдясно&quot;. При периферната лезия е засегнат **целият лицев мускуларен спектър** от съответната страна:\n* **Горен клон:** Невъзможност за сбръчкване на челото и невъзможност за затваряне на окото (лагофталм).\n* **Долен клон:** Увиснал устен ъгъл и изтичане на течности.\n* *Забележка:* При централна лезия (инсулт) челото остава подвижно, защото горният клон има двустранна инервация от кората!\n### **Б. Негативни находки (Важно!)**\n* **Бабински (-) и липса на ЛП:** Това категорично изключва пирамидна увреда (инсулт). Въпреки АН 150/80, патологичният процес е локализиран в самия нерв, а не в главния мозък.\n* **Език по средна линия (n. hypoglossus):** Потвърждава, че няма ангажиране на други черепно-мозъчни нерви, което е типично за идиопатичната парализа на Бел.\n---\n## 3. Патология и поведение (Tips)\n* **Етиология:** Най-често се дължи на оток на нерва в неговия тесен костен канал, често провокиран от вирусна инфекция (Herpes Simplex) или простуда.\n* **Симптом на Бел:** При опит за затваряне на окото, булбусът се извърта нагоре и се вижда само бялата склера (поради лагофталма).\n* **Лечение:** В първите 48-72 часа е критично включването на **Кортикостероиди** за намаляване на отока на нерва.\" id=\"note-1776074176540-2\">Пример 3</span></h1><p><strong>АНАМНЕЗА</strong>: Снета по данни на болната и ПМД. Постъпва за първи път. На 11.04.2026 г. при прием на течности забелязала изтичането им от десния устен ъгъл и променен вкус. Обективно установила лицева асиметрия. Съобщава за неприятен шум (хиперакузис) в дясното ухо. Екип на ЦСМП измерва АН 150/80. Транспортирана до СПО, консултирана от невролог и приета за уточняване и лечение.</p><p>Минали заболявания: Хипертонична болест (ХБ).</p><p><strong>ОБЕКТИВНО СТАТУС</strong>: Жена на видима възраст, отговаряща на календарната. Ало- и автоориентирана. Афебрилна. ДС: вез. дишане, без хрипове. ССС: ритмична сърдечна дейност; АН 150/80; СЧ 98/мин. Корем: мек, неболезнен. Крайници: без отоци.</p><p><strong>НЕВРОЛОГИЧЕН СТАТУС</strong>: МРД: липсва. ЧМН: зеници еднакви, реагиращи на светлина; очни булбуси подвижни във всички посоки. Парализа на Бел вдясно (периферна лезия на VII ЧМН), по-изразена за долния клон; език по средна линия. ДД: ПЛП без парези. СНР: умерено живи Л=Д. ПР: Бабински (-) двустранно. Сетивност: съхранена. Координация: НПП изпълнява правилно. ТР: контролира. ВКФ: съхранени.</p><h1><span class=\"editor-note\" data-note=\"# Клиничен анализ: Случай №4 (Остър исхемичен инсулт в дясното полукълбо)\n## 1. Фокус върху Анамнезата (Динамика на симптомите)\n* **Внезапно начало:** Симптомите започват в рамките на 30 минути – от леко изтръпване до пълна невъзможност за движение. Това е типично за **съдов инцидент**.\n* **Терапевтичен прозорец:** Пациентът усеща симптомите в 09:30 ч. Пристигането в болницата в този времеви пояс е критично за провеждане на тромболиза (разбиване на съсирека).\n* **Рисков профил:** Възрастта (61 г.) е значим фактор за атеросклероза или предсърдно мъждене.\n---\n## 2. Патофизиологичен и патоморфологичен анализ\n### **А. Централна лезия на ЧМН (VII и XII)**\n* **VII ЧМН (Лицев нерв):** Парезата е от централен тип вляво – засяга се само долният клон (устата е изкривена, но челото се движи).\n* **XII ЧМН (Подезичен нерв):** Езикът се отклонява към парализираната страна (вляво). Това потвърждава локализация в дясното мозъчно полукълбо (прецентралната извивка).\n### **Б. Двигателна дейност: Централна хемипареза**\n* **Локализация:** Дясно мозъчно полукълбо -&gt; Кръстосване на пирамидния път в продълговатия мозък -&gt; Парализа на левите крайници.\n* **Бабински (+):** Патогномоничен белег за увреждане на **пирамидния път**. Появата му в острия стадий потвърждава централния произход на парезата.\n### **В. Висши корови функции: Хемиигнориране (Neglect syndrome)**\nТова е един от най-интересните и тежки феномени при засягане на **десния теменен лоб** (париетална кора). Пациентът &quot;игнорира&quot; лявата половина на пространството или собственото си тяло – той не възприема нищо, което се намира вляво от него, въпреки че зрението му може да е съхранено.\n---\n## 3. Обобщение за практиката\n* **Диагноза:** Исхемичен мозъчен инсулт в басейна на дясна ACM.\n* **Патология:** Остра исхемия води до некроза на невроните в моторната кора и вътрешната капсула (*capsula interna*).\n* **Поведение:** Спешен КТ на глава за изключване на кръвоизлив и оценка на годността за тромболитична терапия.\" id=\"note-1776074342190-3\">Пример 4</span></h1><p><strong>АНАМНЕЗА</strong>: Касае се за пациент на 61 г. Съобщава, че сутринта около 09:00 ч. усетил изтръпване в лявата ръка и общо неразположение. Около 09:30 ч. забелязал, че не може да движи ръката си (опит за ползване на дистанционно). По данни на близките пациентът е бил дезориентиран и се е чувствал зле.</p><p><strong>ОБЕКТИВНО СЪСТОЯНИЕ</strong>: МРД: липсва. ЧМН: зеници еднакви, реагиращи на светлина; очни булбуси подвижни във всички посоки, без нистагъм и диплопия. Централна лезия на VII и XII ЧМН вляво. ДД: ПЛП – тежка лявостранна централна хемипареза. СНР: умерено живи Л=Д. Бабински (+) вляво. Сетивност: съхранена. Координация: НПП изпълнява правилно (с десен крайник). ТР: контролира. ВКФ: налице пространствено хемиигнориране (neglect синдром).</p><h1><span class=\"editor-note\" data-note=\"# Клиничен анализ: Случай №5 (Масивен инсулт в лява СМА / Лява хемисфера)\n## 1. Фокус върху Анамнезата (Wake-up Stroke)\n* **Времеви интервал:** Пациентът е бил добре в полунощ, но е открит сутринта в безпомощно състояние. Това се дефинира като **&quot;Wake-up stroke&quot;** (инсулт при събуждане). Тъй като точното време на началото е неизвестно, тези пациенти често изпадат от стандартния прозорец за тромболиза, освен ако не се направи перфузионно изследване.\n* **Рисков профил:** АН 190/90 е екстремно висока стойност, която може да бъде както причина за инсулта (хипертоничен мозъчен кръвоизлив), така и реакция на организма към исхемията.\n---\n## 2. Патофизиологичен и патоморфологичен анализ\n### **А. Десностранна Хемиплегия**\nЗа разлика от предния случай (хемипареза - слабост), тук имаме **хемиплегия** (пълна липса на движения). * **Локализация:** Масивна лезия в лявото полукълбо, обхващаща моторната кора или *capsula interna*. Тъй като пирамидният път се кръстосва, се парализира дясната половина на тялото.\n* **Рефлекси:** Оживените СНР и Бабински (+) вдясно са категорични белези за увреда на горния мотоневрон.\n### **Б. Сетивно-моторна афазия (СМА)**\nТова е най-тежкото нарушение на висшите корови функции. При десноръки хора (и 70% от леворъките) центровете на речта са в **лявото полукълбо**:\n* **Моторна афазия (Брока):** Пациентът разбира, но не може да произнесе нито дума.\n* **Сензорна афазия (Вернике):** Пациентът не разбира нито чуждата реч, нито собствената си.\n* **Пълна СМА:** Комбинация от двете – пълна невъзможност за езикова комуникация.\n### **В. Централна лезия на VII ЧМН**\nПодобно на предния случай, устата е изкривена вдясно (долния мимически етаж), докато инервацията на челото е запазена. Това е сигурен белег за мозъчна (централна), а не нервна (периферна) увреда.\n---\n## 3. Обобщение за практиката\n* **Основна диагноза:** Остър исхемичен/хеморагичен инсулт в лява средна мозъчна артерия (ACM).\n* **Патология:** Масивен оток на лявото полукълбо, водещ до компресия на речевите и моторните центрове.\n* **Спешност:** Необходим е незабавен КТ на глава, за да се разграничи исхемия от масивен хеморагичен инцидент, предвид високото кръвно налягане.\" id=\"note-1776074512907-4\">Пример 5</span></h1><p><strong>АНАМНЕЗА</strong>: Доведен с екип на ЦСМП. Данни от близките – до 00:00 ч. снощи пациентът е бил в добро общо състояние, контактен и самообслужващ се (работил на компютър). Тази сутрин открит в безпомощно състояние, с моторна афазия и липса на движения в десните крайници. От ЦСМП е измерено АН до 190/90.</p><p><strong>ОБЕКТИВНО СЪСТОЯНИЕ: </strong>МРД: липсва. ЧМН: очни булбуси подвижни във всички посоки, без нистагъм и диплопия. Лезия на VII ЧМН от централен тип вдясно; език по срединна линия. ДД: ПЛП – десностранна централна хемиплегия. СНР: оживени вдясно. Бабински (+) вдясно. НПП: не се изследва достоверно. ТР: контролира. ВКФ: Пълна сетивно-моторна афазия (СМА).</p><br>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
